qry:select.qry:xquery:
for $r in SQL('select t.e_duracion, ut.e_minutos from pry04_trabajos as t, pry02_tareas_rec as tr, pry03_und_tiempo as ut
join tr.oi_tarea_rec inner t.oi_tarea_rec, t.oi_unidad_tiempo inner ut.oi_unidad_tiempo where t.f_fecha >= {DateTime(#PARAMIN:@f_desde)} and t.f_fecha <= {DateTime(#PARAMIN:@f_hasta)} and tr.oi_recurso={#SOURCE:@oi_recurso}
')/ROWS/ROW

for $r in SQL('select t.e_duracion, ut.e_minutos from pry04_trabajos as t, pry02_tareas_rec as tr, pry03_und_tiempo as ut
join tr.oi_tarea_rec inner t.oi_tarea_rec, t.oi_unidad_tiempo inner ut.oi_unidad_tiempo where t.f_fecha >= {DateTime(#PARAMIN:@f_desde)} and t.f_fecha <= {DateTime(#PARAMIN:@f_hasta)} and tr.oi_recurso={#SOURCE:@oi_recurso} and t.oi_perfil={#SOURCE:@oi_perfil}
')/ROWS/ROW
